import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.HttpRequest
import akka.stream.Materializer

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system = ActorSystem()
    implicit val materializer = Materializer.create(system)

    val route = Http().route {
      case req @ POST =>
        val userUrl = req.entity.asInstanceOf[HttpRequest].uri
        val responseFuture = Http().singleRequest(HttpRequest(uri = userUrl))
        responseFuture.onComplete {
          case Success(response) =>
            response.discardEntityBytes()
            println(s"Received response from $userUrl")
          case Failure(error) =>
            println(s"Failed to receive response from $userUrl: ${error.getMessage}")
        }
    }
  }
}